/// <summary>FNV hash of the last GametypeStatusBlock sent to this client (0 = never) — the per-mode
/// round/objective HUD stats (T53) are personalized (the KH "31 = self" slot, the SURV hunter
/// visibility), so each peer gates on the hash of ITS OWN serialized block, resending only when the
/// bytes change.</summary>
public uint LastModeStatusHash;

/// <summary>Reusable scratch for the per-peer personalized GametypeStatusBlock (T53) — serialized first so
/// it can be hash-gated before deciding to copy it into the snapshot.</summary>
private readonly BitWriter _modeStatusScratch = new(256);

// Gametype status (T53): the per-mode round/objective HUD stats — QC STAT(REDALIVE..PINKALIVE)
// (CA/FT), STAT(OBJECTIVE_STATUS) (the KH key pack), eliminatedPlayers (scoreboard grey-out) and
// survivalStatuses (role + hunter disclosure). The block is PERSONALIZED per recipient (the KH
// "31 = self" slot, the SURV hunter visibility), so serialize per peer into a scratch and hash-gate
// (steady-state cost = one bool; QC's equivalent is stat delta-compression + linked-entity SendFlags).
_modeStatusScratch.Reset();
bool haveModeStatus = XonoticGodot.Net.GametypeStatusBlock.Capture(
    _modeStatusScratch, _world.GameType, owner, _world.Clients.Players, NetIdFor,
    roundStarted: _world.Rounds is { IsRoundStarted: true });
uint modeStatusHash = haveModeStatus ? XonoticGodot.Net.GametypeStatusBlock.Hash(_modeStatusScratch.WrittenSpan) : 0u;
bool sendModeStatus = haveModeStatus && st.LastModeStatusHash != modeStatusHash;
_snapshotWriter.WriteBool(sendModeStatus);
if (sendModeStatus)
{
    _snapshotWriter.WriteBytes(_modeStatusScratch.WrittenSpan);
    st.LastModeStatusHash = modeStatusHash;
}

/// <summary>The latest per-mode round/objective HUD status (T53): the CA/FT alive counts + eliminated ids,
/// the KH OBJECTIVE_STATUS key pack, the Survival role + disclosed hunter ids. Null until a tracked mode
/// sends one. Consumers: NetGame.UpdateModIcons (ModIconsPanel) + UpdateScoreboard (eliminated grey-out).</summary>
public XonoticGodot.Net.GametypeStatusBlock.Decoded? LatestModeStatus { get; private set; }

// Gametype status (T53): read in lockstep with ServerNet's write order (owner → movevars → scoreinfo →
// scoreboard → THIS → entity section). ALWAYS consume the bytes to keep the stream aligned, even with
// no consumer wired (the ScoreInfo comment above documents the alignment contract).
if (r.ReadBool())
{
    XonoticGodot.Net.GametypeStatusBlock.Decoded? ms = XonoticGodot.Net.GametypeStatusBlock.Deserialize(ref r);
    if (ms is not null && !r.BadRead)
        LatestModeStatus = ms;
}

private XonoticGodot.Net.GametypeStatusBlock.Decoded? _lastFedModeStatus;

/// <summary>Feed + toggle the mod-icons panel (QC HUD_ModIcons_SetFunc → gametype.m_modicons) from the
/// networked per-mode status (T53). Cheap: property writes + a Visible toggle; the panel repaints itself.</summary>
private void UpdateModIcons()
{
    if (_fullHud is null || _client is null)
        return;
    ModIconsPanel panel = _fullHud.ModIcons;
    XonoticGodot.Net.GametypeStatusBlock.Decoded? ms = _client.LatestModeStatus;
    if (ms is null)
    {
        if (panel.Visible) panel.Visible = false;
        return;
    }
    switch (ms.Mode)
    {
        case XonoticGodot.Net.GametypeStatusBlock.Kind.ClanArena:
            panel.Mode = ModIconsPanel.ModIconsMode.ClanArena;
            panel.SetAliveCounts(ms.Alive[0], ms.Alive[1], ms.Alive[2], ms.Alive[3]);
            break;
        case XonoticGodot.Net.GametypeStatusBlock.Kind.FreezeTag:
            panel.Mode = ModIconsPanel.ModIconsMode.FreezeTag;
            panel.SetAliveCounts(ms.Alive[0], ms.Alive[1], ms.Alive[2], ms.Alive[3]);
            break;
        case XonoticGodot.Net.GametypeStatusBlock.Kind.KeyHunt:
            panel.Mode = ModIconsPanel.ModIconsMode.Keyhunt;
            panel.ObjectiveStatus = unchecked((int)ms.KeyState);
            break;
        case XonoticGodot.Net.GametypeStatusBlock.Kind.Survival:
            panel.Mode = ModIconsPanel.ModIconsMode.Survival;
            panel.SurvivalStatus = ms.MyStatus;
            break;
        default:
            panel.Mode = ModIconsPanel.ModIconsMode.None;
            break;
    }
    panel.MyTeam = ms.MyTeamIndex;
    if (ms.TeamCount > 0) panel.TeamCount = ms.TeamCount;
    bool show = panel.Mode != ModIconsPanel.ModIconsMode.None;
    if (panel.Visible != show)
        panel.Visible = show;
}

// feed rows only when the data changed (identity by reference — ClientNet replaces the object per
// decode). A mode-status change (T53) also re-feeds: the eliminated grey-out must track freezes/deaths
// that don't bump a score version.
XonoticGodot.Net.ScoreboardWire? sb = _client.LatestScoreboard;
XonoticGodot.Net.GametypeStatusBlock.Decoded? ms = _client.LatestModeStatus;
if (sb is not null && (!ReferenceEquals(sb, _lastFedScoreboard) || !ReferenceEquals(ms, _lastFedModeStatus)))
{
    _lastFedScoreboard = sb;
    _lastFedModeStatus = ms;
    _scoreboard.Title = ScoreboardTitle();
    _scoreboard.SetWireRows(sb, _client.LocalNetId, ms?.EliminatedNetIds); // grey-out (QC eliminatedPlayers)
    FeedScoreboardHeader();
}
